             { label: '正答率', val: `${result.accuracy.toFixed(1)}%`, sub: 'ACCURACY', color: 'text-[#e10600]' },
             { label: '正解数', val: `${result.details.filter(d => d.isCorrect).length}`, sub: `OF ${result.details.length} Qs`, color: 'text-slate-900' },
