            <div className="flex-1 h-px bg-slate-100" style={{ backgroundColor: '#f1f5f9' }}></div>
          </div>
          <div className={`grid grid-cols-${colCount} gap-6`} style={{ backgroundColor: '#ffffff' }}>
            {columns.map((colItems, idx) => (
              <div key={idx} className="overflow-hidden" style={{ backgroundColor: '#ffffff' }}>
                <table className="w-full text-left table-fixed border-collapse">
                  <thead><TableHeader /></thead>
                  <tbody style={{ backgroundColor: '#ffffff' }}>
                    {colItems.map((d) => (
                      <TableRow key={d.questionNumber} d={d} />
                    ))}
                  </tbody>
                </table>
              </div>
            ))}
          </div>
        </div>

        {/* Visual Roadmap - 改ページ禁止 */}
        <div className="bg-slate-900 p-2 border-l-4 border-[#00ffd2] mt-4 mb-2 shrink-0 avoid-break" style={{ backgroundColor: '#0f172a' }}>
          <div className="flex h-2 gap-0.5">
            {result.details.map((d, i) => (
              <div key={i} className={`flex-1 skew-x-[-15deg]`} style={{ backgroundColor: d.isCorrect ? '#00ffd2' : '#e10600' }} />
            ))}
