        </div>

        {/* Footer - 改ページ禁止 */}
        <div className="flex justify-between items-end pt-2 border-t border-slate-100 shrink-0 avoid-break" style={{ backgroundColor: '#ffffff' }}>
           <div className="text-[7px] text-slate-300 italic font-bold uppercase tracking-tighter" style={{ color: '#cbd5e1' }}>
             FIA DATA STREAM // END OF SESSION ANALYSIS // ALL SYSTEMS NOMINAL
           </div>
           <div className="bg-slate-800 text-white px-3 py-1 f1-font font-black italic text-[8px] skew-x-[-10deg]" style={{ backgroundColor: '#1e293b', color: '#ffffff' }}>
             OFFICIAL RESULT
           </div>
        </div>
