                    <button onClick={clearSelection} className="px-3 py-1 text-[8px] font-black text-white/40 hover:text-[#e10600] transition-colors uppercase">Clear</button>
                  </div>
                  <button onClick={() => triggerLapChange(2)} className="bg-white/5 border border-white/10 text-white px-4 py-2 text-[10px] font-black italic rounded uppercase transition-colors"><i className="fa-solid fa-sliders mr-2"></i>MODIFY SETUP</button>
                  <button onClick={() => triggerLapChange(4)} className="bg-white/5 border border-white/10 text-white px-4 py-2 text-[10px] font-black italic rounded uppercase transition-colors">INDIVIDUAL DATA</button>
                  <div className="flex bg-black/40 p-1 rounded">
