                   <div className="absolute top-0 right-0 w-32 h-32 bg-[#e10600]/5 -mr-16 -mt-16 rounded-full group-hover:scale-150 transition-transform"></div>
                   <div className="flex items-center space-x-6">
                      <div className="w-20 h-20 bg-[#e10600] rounded-lg flex items-center justify-center shadow-[0_0_30px_rgba(225,6,0,0.3)]">
                        <i className="fa-solid fa-plus text-4xl text-white group-hover:scale-125 transition-transform"></i>
                      </div>
                      <div>
                        <h2 className="f1-font text-3xl font-black italic uppercase text-white leading-none mb-2">NEW SESSION</h2>
                        <p className="text-white/40 text-xs font-bold tracking-widest uppercase">Start a clean slate analysis</p>
                      </div>
                   </div>
                </div>

                <div onClick={continueCurrentSession} className={`bg-[#1f1f27] border-2 border-white/5 p-10 rounded-xl cursor-pointer hover:border-[#00ffd2] group transition-all relative overflow-hidden ${!hasDraft ? 'opacity-20 grayscale cursor-not-allowed' : ''}`}>
                   <div className="absolute top-0 right-0 w-32 h-32 bg-[#00ffd2]/5 -mr-16 -mt-16 rounded-full group-hover:scale-150 transition-transform"></div>
                   <div className="flex items-center space-x-6">
                      <div className="w-20 h-20 bg-[#00ffd2] rounded-lg flex items-center justify-center shadow-[0_0_30px_rgba(0,255,210,0.3)]">
                        <i className="fa-solid fa-play text-4xl text-black group-hover:scale-125 transition-transform"></i>
