        {lap <= 3 && showSetupEntry && (
          <div className="flex-1 flex flex-col overflow-hidden">
             <SetupForm lap={lap as 1|2|3} setLap={triggerLapChange} students={students} setStudents={setStudents} questions={questions} setQuestions={setQuestions} onProcess={handleProcessAnswers} sessionTitle={sessionTitle} setSessionTitle={setSessionTitle} resetSession={resetAllState} />
          </div>
