        {lap === 4 && selectedFullResult && (
          <div className="flex-1 flex gap-6 overflow-hidden">
            <div className="w-64 bg-[#1f1f27] rounded flex flex-col no-print border border-white/5">
              <div className="p-4 border-b border-white/10 bg-black/20">
                <p className="text-[9px] font-black italic text-[#e10600] uppercase mb-3">Filters</p>
                <div className="space-y-3">
                  <select value={sbClassFilter} onChange={(e) => { setSbClassFilter(e.target.value); setSelectedResultIndex(0); }} className="w-full bg-black text-[11px] text-white border border-white/20 p-2 rounded outline-none focus:border-[#00ffd2] cursor-pointer">
                    <option value="">クラス: すべて</option>
                    {sortedClassNames.map(v => <option key={v} value={v}>{v}</option>)}
                  </select>
                  <div className="flex bg-black/40 p-0.5 rounded border border-white/10">
                    <button onClick={() => setSbSortBy('id')} className={`flex-1 py-1 text-[9px] font-black rounded transition-all ${sbSortBy === 'id' ? 'bg-[#e10600]' : 'text-white/30'}`}>ID順</button>
                    <button onClick={() => setSbSortBy('score')} className={`flex-1 py-1 text-[9px] font-black rounded transition-all ${sbSortBy === 'score' ? 'bg-[#e10600]' : 'text-white/30'}`}>成績順</button>
                  </div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto compact-scroll p-1">
                {sidebarList.map((r, idx) => (
                  <div key={r.student.id} className={`driver-list-item ${selectedResultIndex === idx ? 'active' : ''}`}>
                    <div className={`checkbox-custom ${selectedIds.has(r.student.id) ? 'checked' : ''}`} onClick={(e) => { e.stopPropagation(); toggleSelection(r.student.id); }}></div>
                    <div className="flex-1" onClick={() => setSelectedResultIndex(idx)}>
                      <div className="flex justify-between items-center"><span className="text-[11px] font-black italic uppercase text-white truncate mr-2">{r.student.name}</span><span className="text-[8px] font-bold text-white/20">{r.student.id}</span></div>
                      <div className="flex justify-between items-center mt-1"><span className="text-[9px] text-[#00ffd2] font-black">{r.score} PTS</span><span className="text-[9px] text-white/30 uppercase">{r.student.class}</span></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div className="flex-1 flex flex-col overflow-hidden">
              <div className="flex justify-between items-center mb-4 no-print">
                <div className="flex items-center space-x-3"><h2 className="text-xl font-black italic text-white uppercase tracking-tighter f1-font">Analysis Terminal</h2></div>
                <div className="flex items-center space-x-2">
                  <button onClick={() => triggerLapChange(2)} className="bg-white/5 hover:bg-white/10 text-white px-4 py-2 font-black italic rounded text-[10px] border border-white/10 uppercase tracking-widest tracking-tighter"><i className="fa-solid fa-sliders mr-2"></i>Modify Setup</button>
                  <button onClick={() => triggerLapChange(5)} className="bg-[#00ffd2] text-black px-4 py-2 font-black italic rounded text-[10px] f1-font hover:scale-105 active:scale-95 uppercase">Full Standings <i className="fa-solid fa-trophy ml-1"></i></button>
                </div>
              </div>
              <div className="flex-1 flex flex-col overflow-y-auto compact-scroll shadow-2xl bg-white/5 rounded-sm">
                 <ResultReport result={selectedFullResult} sessionTitle={sessionTitle} />
              </div>
            </div>
          </div>
        )}

        {lap === 5 && (
          <div className="flex-1 flex flex-col overflow-hidden">
            <div className="flex justify-between items-end mb-6">
               <div>
                  <h1 className="text-4xl font-black italic text-white uppercase tracking-tighter f1-font">{filterClass ? `${filterClass} STANDINGS` : (sessionTitle || "WORLD CHAMPIONSHIP STANDINGS")}</h1>
                  <p className="text-[#00ffd2] text-[10px] font-black italic tracking-widest uppercase mt-1">Classification // Official Final Results</p>
               </div>
               <div className="flex space-x-3 items-center">
                  <div className="flex items-center space-x-1 mr-2 bg-white/5 p-1 rounded border border-white/10">
                    <button onClick={selectAllInStandings} className="px-3 py-1 text-[8px] font-black text-white hover:text-[#00ffd2] transition-colors uppercase">Select All</button>
                    <button onClick={clearSelection} className="px-3 py-1 text-[8px] font-black text-white/40 hover:text-[#e10600] transition-colors uppercase">Clear</button>
                  </div>
                  <button onClick={() => triggerLapChange(2)} className="bg-white/5 border border-white/10 text-white px-4 py-2 text-[10px] font-black italic rounded uppercase"><i className="fa-solid fa-sliders mr-2"></i>MODIFY SETUP</button>
                  <button onClick={() => triggerLapChange(4)} className="bg-white/5 border border-white/10 text-white px-4 py-2 text-[10px] font-black italic rounded uppercase">INDIVIDUAL DATA</button>
                  <div className="flex bg-black/40 p-1 rounded">
                    {['score', 'id'].map(m => (<button key={m} onClick={() => setSortBy(m as any)} className={`px-4 py-1 text-[9px] font-black rounded transition-all ${sortBy === m ? 'bg-[#e10600]' : 'text-white/40'}`}>{m.toUpperCase()}</button>))}
                  </div>
               </div>
            </div>
            <div className="flex-1 overflow-y-auto compact-scroll space-y-px">
              {finalSortedStandings.map((r) => {
                const absRank = rankMap.get(r.student.id) || 0;
                return (
                  <div key={r.student.id} className="moto-row">
                    <div className="moto-checkbox-cell" onClick={() => toggleSelection(r.student.id)}>
                      <div className={`checkbox-custom mr-0 ${selectedIds.has(r.student.id) ? 'checked' : ''}`}></div>
                    </div>
                    <div className={`moto-pos ${absRank === 1 ? 'top1' : absRank === 2 ? 'top2' : absRank === 3 ? 'top3' : ''}`} onClick={() => { 
                        const idx = sidebarList.findIndex(res => res.student.id === r.student.id);
                        if (idx !== -1) setSelectedResultIndex(idx);
                        triggerLapChange(4); 
                      }}>{absRank}</div>
                    <div className="moto-pts">{r.score}</div>
                    <div className="moto-name-block" onClick={() => { 
                        const idx = sidebarList.findIndex(res => res.student.id === r.student.id);
                        if (idx !== -1) setSelectedResultIndex(idx);
                        triggerLapChange(4); 
                      }}>
                       <div className="moto-team-color" style={{ backgroundColor: getClassColor(r.student.class) }}></div>
                       <span className="moto-driver">{r.student.name}</span>
                       <span className="moto-team">{r.student.class}</span>
                    </div>
                    <div className="moto-stat">{r.accuracy.toFixed(1)}%</div>
                  </div>
                );
              })}
            </div>
            <div className="mt-8 grid grid-cols-4 gap-4">
               <div className="bg-[#1f1f27] p-5 rounded border-l-4 border-[#00ffd2]">
                  <p className="text-[10px] font-black text-white/30 uppercase tracking-widest">Average Score</p>
                  <p className="text-3xl font-black italic f1-font text-[#00ffd2]">{overallAverage.toFixed(1)}</p>
               </div>
               <div className="bg-[#1f1f27] p-5 rounded border-l-4 border-[#e10600]">
                  <p className="text-[10px] font-black text-white/30 uppercase tracking-widest">Total Drivers</p>
                  <p className="text-3xl font-black italic f1-font">{results.length}</p>
               </div>
               <div className="col-span-2 bg-[#1f1f27] p-5 rounded flex items-center justify-between">
                  <div className="flex items-center space-x-8">
                    {sortedClassNames.slice(0, 4).map(cls => (
                      <div key={cls} className="flex flex-col cursor-pointer hover:opacity-80 transition-all" onClick={() => setFilterClass(cls)}>
                        <span className="text-[9px] font-black text-white/20 uppercase">{cls}</span>
                        <span className="font-black italic text-lg" style={{ color: getClassColor(cls) }}>
                          { classStats[cls] ? (classStats[cls].totalScore / classStats[cls].count).toFixed(1) : "0.0" }
                        </span>
                      </div>
                    ))}
                  </div>
                  <span className="text-[10px] font-black italic text-white/10 uppercase tracking-widest">Constructor Metrics</span>
               </div>
            </div>
          </div>
        )}
      </main>
      <footer className="h-8 bg-[#060c22] border-t border-white/5 flex items-center px-8 no-print shrink-0 justify-between">
        <div className="text-[8px] font-bold text-white/20 uppercase tracking-widest">FIA APEX DATA STREAM // VER 6.0 // PERSISTENCE ACTIVE</div>
        <div className="text-[8px] font-bold text-white/20 uppercase tracking-widest f1-font italic">Copyright © Ken Magami. All Rights Reserved.</div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Student, Question, StudentAnswer, ScoringResult, ArchiveData, CompetencyType, COMPETENCY_LABELS } from './types';
import { SetupForm } from './components/SetupForm';
import { ResultReport } from './components/ResultReport';

const LOGO_PATH = "/logo.png";
const APP_VERSION = "v1.2.5-PRO-GP";

