const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [results, setResults] = useState<ScoringResult[]>([]);
  const [rawAnswers, setRawAnswers] = useState<StudentAnswer[]>([]);
  const [lap, setLap] = useState<1 | 2 | 3 | 4 | 5>(1);
  const [isAnimating, setIsAnimating] = useState(false);
  const [archives, setArchives] = useState<ArchiveData[]>([]);
  const [selectedResultIndex, setSelectedResultIndex] = useState<number>(0);
  const [sessionTitle, setSessionTitle] = useState<string>("");
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [sortBy, setSortBy] = useState<'score' | 'id'>('score');
  const [filterClass, setFilterClass] = useState<string | null>(null);
  const [sbClassFilter, setSbClassFilter] = useState<string>("");
  const [sbSortBy, setSbSortBy] = useState<'id' | 'score'>('id');
  const [showExportModal, setShowExportModal] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [exportMode, setExportMode] = useState<'all' | 'single' | 'selected' | null>(null);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [showTutorial, setShowTutorial] = useState(false);
  const [tutorialHiddenForever, setTutorialHiddenForever] = useState(false);
  const [showSetupEntry, setShowSetupEntry] = useState(false);

  const refreshArchives = useCallback(() => {
    try {
      const savedArchives = localStorage.getItem('grader_archives');
      if (savedArchives) setArchives(JSON.parse(savedArchives));
      const hidden = localStorage.getItem('grader_tutorial_hidden') === 'true';
      setTutorialHiddenForever(hidden);
    } catch (e) { console.error("Archive load failed", e); }
  }, []);

  useEffect(() => {
    refreshArchives();
    const draft = localStorage.getItem('grader_current_draft');
    if (draft) {
      try {
        const data = JSON.parse(draft);
        if (data.students) setStudents(data.students);
        if (data.questions) setQuestions(data.questions);
        if (data.sessionTitle) setSessionTitle(data.sessionTitle);
        if (data.results) setResults(data.results);
        if (data.rawAnswers) setRawAnswers(data.rawAnswers);
        if (data.currentSessionId) setCurrentSessionId(data.currentSessionId);
      } catch (e) { console.error("Draft load failed", e); }
    }

    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, [refreshArchives]);

  const startNewSession = () => {
    if (students.length > 0 || questions.length > 0) {
      if (!confirm("現在のドラフト設定を破棄して、新しいセッションを開始しますか？")) return;
    }
    setStudents([]);
    setQuestions([]);
    setResults([]);
    setRawAnswers([]);
    setSessionTitle("");
    setCurrentSessionId(null);
    setSelectedResultIndex(0);
    localStorage.removeItem('grader_current_draft');

    setShowSetupEntry(true);
    setLap(1);
  };

  const continueCurrentSession = () => {
    setShowSetupEntry(true);
  };

  const resetAllState = () => {
    setStudents([]);
    setQuestions([]);
    setResults([]);
    setRawAnswers([]);
    setSessionTitle("");
    setCurrentSessionId(null);
    setShowSetupEntry(false);
    localStorage.removeItem('grader_current_draft');
    setLap(1);
  };

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') setDeferredPrompt(null);
  };

  useEffect(() => {
    if (!tutorialHiddenForever) setShowTutorial(true);
  }, [lap, tutorialHiddenForever]);

  const handleDismissTutorial = (forever: boolean) => {
    setShowTutorial(false);
    if (forever) {
      setTutorialHiddenForever(true);
      localStorage.setItem('grader_tutorial_hidden', 'true');
    }
  };

  useEffect(() => {
    const draft = { students, questions, sessionTitle, lap, results, rawAnswers, currentSessionId };
    try {
      localStorage.setItem('grader_current_draft', JSON.stringify(draft));
    } catch (e) { localStorage.removeItem('grader_current_draft'); }
  }, [students, questions, sessionTitle, lap, results, rawAnswers, currentSessionId]);

  const sortedClassNames = useMemo(() => {
    const classes = Array.from(new Set(students.map(s => s.class)));
    return classes.sort();
  }, [students]);

  const rankMap = useMemo(() => {
    const sortedByScore = [...results].sort((a, b) => b.score - a.score || a.student.id.localeCompare(b.student.id));
    const map = new Map<string, number>();
    sortedByScore.forEach((r, idx) => map.set(r.student.id, idx + 1));
    return map;
  }, [results]);

  const sidebarList = useMemo(() => {
    let filtered = [...results];
    if (sbClassFilter) filtered = filtered.filter(r => r.student.class === sbClassFilter);
    return filtered.sort((a, b) => {
      if (sbSortBy === 'score') {
        const rankA = rankMap.get(a.student.id) || 999;
        const rankB = rankMap.get(b.student.id) || 999;
        return rankA - rankB;
      }
      return a.student.id.localeCompare(b.student.id);
    });
  }, [results, sbClassFilter, sbSortBy, rankMap]);

  const navigateDriver = useCallback((dir: number) => {
    if (sidebarList.length === 0) return;
    let nextIdx = selectedResultIndex + dir;
    if (nextIdx < 0) nextIdx = sidebarList.length - 1;
    if (nextIdx >= sidebarList.length) nextIdx = 0;
    setSelectedResultIndex(nextIdx);
  }, [sidebarList, selectedResultIndex]);

  const triggerLapChange = (nextLap: 1 | 2 | 3 | 4 | 5) => {
    if (lap === 2 && nextLap === 3) saveToArchive(results, rawAnswers);

    // Lap 2 または 3 に戻る際は Setup 画面を確実に表示させるためのロジック
    if (nextLap >= 1 && nextLap <= 3) {
      setShowSetupEntry(true);
    }

    setIsAnimating(true);
    setTimeout(() => {
      setLap(nextLap);
      if (nextLap === 1) {
        // ヘッダーロゴから戻ったときなどは一旦Dashboard状態にする
        setShowSetupEntry(false);
        refreshArchives();
      }
      setTimeout(() => setIsAnimating(false), 300);
    }, 300);
  };

  const overallQuestionStats = useMemo(() => {
    const stats: Record<number, number> = {};
    if (rawAnswers.length === 0) return stats;
    questions.forEach(q => {
      let correct = 0; rawAnswers.forEach(ans => { if (ans.answers[q.number] === q.correctAnswer) correct++; });
      stats[q.number] = (correct / rawAnswers.length) * 100;
    });
    return stats;
  }, [rawAnswers, questions]);

  const overallAverage = useMemo(() => {
    if (results.length === 0) return 0;
    return results.reduce((acc, r) => acc + r.score, 0) / results.length;
  }, [results]);

  const classStats = useMemo(() => {
    const stats: Record<string, { totalScore: number; count: number }> = {};
    results.forEach(r => {
      const cls = r.student.class;
      if (!stats[cls]) stats[cls] = { totalScore: 0, count: 0 };
      stats[cls].totalScore += r.score;
      stats[cls].count += 1;
    });
    return stats;
  }, [results]);

  const getFullDetailResult = useCallback((r: ScoringResult) => {
    const ans = rawAnswers.find(a => a.studentId === r.student.id);
    if (!ans) return r;
    const details = questions.map(q => ({
      questionNumber: q.number, correctAnswer: q.correctAnswer, studentAnswer: ans.answers[q.number] || "",
      isCorrect: ans.answers[q.number] === q.correctAnswer, point: q.point, group: q.group, competency: q.competency, overallAccuracy: overallQuestionStats[q.number]
    }));
    return { ...r, details };
  }, [rawAnswers, questions, overallQuestionStats]);

  const selectedFullResult = useMemo(() => {
    const summary = sidebarList[selectedResultIndex];
    if (!summary) return null;
    return getFullDetailResult(summary);
  }, [sidebarList, selectedResultIndex, getFullDetailResult]);

  const finalSortedStandings = useMemo(() => {
    let data = filterClass ? results.filter(r => r.student.class === filterClass) : results;
    if (sortBy === 'score') return data.sort((a, b) => (rankMap.get(a.student.id) || 0) - (rankMap.get(b.student.id) || 0));
    return data.sort((a, b) => a.student.id.localeCompare(b.student.id));
  }, [results, filterClass, sortBy, rankMap]);

  const handleProcessAnswers = (answers: StudentAnswer[]) => {
    setRawAnswers(answers);
    const newResults: ScoringResult[] = answers.map(ans => {
      const student = students.find(s => s.id === ans.studentId) || { id: ans.studentId, name: '未登録', class: '-' };
      let score = 0; let totalPoints = 0;
      const compMap: Record<CompetencyType, { score: number; total: number }> = { 
        none: { score: 0, total: 0 }, knowledge: { score: 0, total: 0 }, thinking: { score: 0, total: 0 }, attitude: { score: 0, total: 0 } 
      };
      questions.forEach(q => {
        const isCorrect = ans.answers[q.number] === q.correctAnswer;
        totalPoints += q.point;
        if (q.competency) compMap[q.competency].total += q.point;
        if (isCorrect) { score += q.point; if (q.competency) compMap[q.competency].score += q.point; }
      });
      const competencyResults: any = {};
      (Object.keys(compMap) as CompetencyType[]).forEach(k => {
        competencyResults[k] = { label: COMPETENCY_LABELS[k], score: compMap[k].score, total: compMap[k].total, percentage: compMap[k].total > 0 ? (compMap[k].score / compMap[k].total) * 100 : 0 };
      });
      return { student, score, totalPoints, accuracy: totalPoints > 0 ? (score / totalPoints) * 100 : 0, competencyResults, details: [] };
    });
    setResults(newResults);
    saveToArchive(newResults, answers);
    setSelectedResultIndex(0);
    triggerLapChange(4);
  };

  const saveToArchive = useCallback((newResults: ScoringResult[], currentRawAnswers: StudentAnswer[]): string => {
    const dateStr = new Date().toLocaleDateString('ja-JP', { month: 'short', day: 'numeric' });
    const finalTitle = sessionTitle || `GP - ${dateStr}`;
    const id = currentSessionId || `session_${Date.now()}`;
    const archiveResults = newResults.map(r => ({ ...r, details: [] }));
    const newArchive: ArchiveData = {
      id, timestamp: new Date().toLocaleString(), name: finalTitle,
      results: archiveResults as any, questions, students, rawAnswers: currentRawAnswers
    };
    try {
      const savedArchives = localStorage.getItem('grader_archives');
      let archiveList: ArchiveData[] = savedArchives ? JSON.parse(savedArchives) : [];
      const existingIndex = archiveList.findIndex(a => a.id === id);
      if (existingIndex > -1) archiveList[existingIndex] = newArchive;
      else archiveList = [newArchive, ...archiveList];
      localStorage.setItem('grader_archives', JSON.stringify(archiveList));
      setArchives(archiveList);
    } catch (e) { alert("保存容量上限です。"); }
    if (!currentSessionId) setCurrentSessionId(id);
    return id;
  }, [currentSessionId, questions, sessionTitle, students]);

  const handleResumeSession = (archive: ArchiveData) => {
    setStudents(archive.students);
    setQuestions(archive.questions);
    setResults(archive.results);
    setRawAnswers(archive.rawAnswers);
    setSessionTitle(archive.name);
    setCurrentSessionId(archive.id);
    setSelectedResultIndex(0);
    if (archive.rawAnswers && archive.rawAnswers.length > 0) {
      triggerLapChange(4);
    } else {
      setShowSetupEntry(true);
      triggerLapChange(2);
    }
  };

  const handleDeleteArchive = useCallback((e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!confirm("このログを消去しますか？（復元できません）")) return;
    try {
      const savedArchives = localStorage.getItem('grader_archives');
      if (!savedArchives) return;
      let archiveList: ArchiveData[] = JSON.parse(savedArchives);
      archiveList = archiveList.filter(a => a.id !== id);
      localStorage.setItem('grader_archives', JSON.stringify(archiveList));
      setArchives(archiveList);
      if (currentSessionId === id) setCurrentSessionId(null);
    } catch (e) { console.error("Delete failed", e); }
  }, [currentSessionId]);

  const handleRenameArchive = useCallback((e: React.MouseEvent, id: string, oldName: string) => {
    e.stopPropagation();
    const newName = prompt("新しいセッション名を入力してください:", oldName);
    if (!newName || newName === oldName) return;
    try {
      const savedArchives = localStorage.getItem('grader_archives');
      if (!savedArchives) return;
      let archiveList: ArchiveData[] = JSON.parse(savedArchives);
      const index = archiveList.findIndex(a => a.id === id);
      if (index > -1) {
        archiveList[index].name = newName;
        localStorage.setItem('grader_archives', JSON.stringify(archiveList));
        setArchives(archiveList);
        if (currentSessionId === id) setSessionTitle(newName);
      }
    } catch (e) { console.error("Rename failed", e); }
  }, [currentSessionId]);

  const toggleSelection = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const selectAllInStandings = () => {
    const ids = finalSortedStandings.map(r => r.student.id);
    setSelectedIds(new Set(ids));
  };

  const clearSelection = () => setSelectedIds(new Set());

  const exportPDF = async (mode: 'all' | 'single' | 'selected') => {
    setShowExportModal(false);
    setIsExporting(true);
    setExportMode(mode);
    setExportProgress(0);
    const targets = mode === 'single' && selectedFullResult ? [selectedFullResult] : mode === 'selected' ? results.filter(r => selectedIds.has(r.student.id)).sort((a, b) => a.student.id.localeCompare(b.student.id)) : [...results].sort((a, b) => a.student.id.localeCompare(b.student.id));
    if (targets.length === 0) { setIsExporting(false); return; }
    const opt = { margin: 0, filename: `${sessionTitle || 'Analysis_Report'}.pdf`, image: { type: 'jpeg', quality: 0.98 }, html2canvas: { scale: 2, useCORS: true, logging: false, backgroundColor: '#ffffff' }, jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' } };
    try {
      await new Promise(r => setTimeout(r, 1000));
      const html2pdf = (window as any).html2pdf;
      let worker = html2pdf().set(opt).from(document.getElementById(`pdf-page-${targets[0].student.id}`)).toPdf();
      setExportProgress(Math.floor((1 / targets.length) * 100));
      for (let i = 1; i < targets.length; i++) {
        const studentId = targets[i].student.id;
        const pageElement = document.getElementById(`pdf-page-${studentId}`);
        if (pageElement) worker = worker.get('pdf').then((pdf: any) => { pdf.addPage(); }).from(pageElement).toContainer().toCanvas().toImg().toPdf();
        setExportProgress(Math.floor(((i + 1) / targets.length) * 100));
        await new Promise(r => setTimeout(r, 100));
      }
      await worker.save();
      setExportProgress(100);
      await new Promise(r => setTimeout(r, 500));
    } catch (err) { alert("PDFの生成に失敗しました。"); } finally { setIsExporting(false); setExportProgress(0); setExportMode(null); }
  };

  const downloadExcel = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const groups = Array.from(new Set(questions.map(q => q.group).filter(g => g !== ""))).sort();
    const competencies = (Object.keys(COMPETENCY_LABELS) as CompetencyType[]).filter(k => k !== 'none');
    let header = "学籍番号,クラス,氏名,合計点,正答率(%)";
    groups.forEach(g => header += `,大問${g}`);
    competencies.forEach(k => header += `,${COMPETENCY_LABELS[k]}`);
    header += "\n";
    let csv = header;
    results.forEach(r => {
      const studentAns = rawAnswers.find(a => a.studentId === r.student.id);
      let row = `${r.student.id},${r.student.class},${r.student.name},${r.score},${r.accuracy.toFixed(1)}`;
      groups.forEach(g => {
        let groupScore = 0;
        questions.filter(q => q.group === g).forEach(q => { if (studentAns?.answers[q.number] === q.correctAnswer) groupScore += q.point; });
        row += `,${groupScore}`;
      });
      competencies.forEach(k => { row += `,${r.competencyResults[k]?.score || 0}`; });
      csv += row + "\n";
    });
    const blob = new Blob([bom, csv], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `${sessionTitle || 'Session_Analysis'}.csv`; a.click();
  };

  const getClassColor = (cls: string) => {
    const colors = ['#e10600', '#00ffd2', '#3671C6', '#FF8000', '#FFF500', '#00D2FF', '#6CD3BF', '#B6BABD'];
    const index = Math.abs(cls.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0)) % colors.length;
    return colors[index];
  };

  const resultsForPdf = useMemo(() => {
    if (!isExporting) return [];
    if (exportMode === 'single' && selectedFullResult) return [selectedFullResult];
    let filtered = [...results];
    if (exportMode === 'selected') filtered = filtered.filter(r => selectedIds.has(r.student.id));
    return filtered.sort((a, b) => a.student.id.localeCompare(b.student.id));
  }, [isExporting, exportMode, selectedFullResult, results, selectedIds]);

  const hasDraft = students.length > 0 || questions.length > 0;

  return (
    <div className={`min-h-screen flex flex-col bg-[#0b0e1b] text-white relative`}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@900&family=Chakra+Petch:wght@300;400;700&display=swap');
        body { font-family: 'Chakra Petch', sans-serif; overflow-x: hidden; }
        .f1-font { font-family: 'Orbitron', sans-serif; }
        .compact-scroll::-webkit-scrollbar { width: 4px; }
        .compact-scroll::-webkit-scrollbar-thumb { background: #444; border-radius: 2px; }
        .moto-row { display: flex; align-items: center; background: rgba(255, 255, 255, 0.03); color: white; margin-bottom: 2px; height: 48px; position: relative; overflow: hidden; cursor: pointer; transition: all 0.2s; border-left: 2px solid transparent; }
        .moto-row:hover { background: rgba(255, 255, 255, 0.08); transform: scale(1.01); border-left-color: #00ffd2; }
        .moto-pos { width: 55px; height: 100%; display: flex; align-items: center; justify-content: center; font-size: 20px; font-weight: 900; font-family: 'Orbitron'; font-style: italic; background: rgba(255,255,255,0.05); clip-path: polygon(0 0, 100% 0, 75% 100%, 0% 100%); margin-right: -10px; z-index: 2; }
        .moto-pos.top1 { color: black; background: linear-gradient(135deg, #ffd700 0%, #b8860b 100%); }
        .moto-pos.top2 { color: black; background: linear-gradient(135deg, #c0c0c0 0%, #808080 100%); }
        .moto-pos.top3 { color: black; background: linear-gradient(135deg, #cd7f32 0%, #8b4513 100%); }
        .moto-pts { width: 80px; text-align: right; padding-right: 20px; font-weight: 900; font-family: 'Orbitron'; font-size: 18px; color: #fff; z-index: 2; }
        .moto-name-block { flex: 1; height: 100%; display: flex; align-items: center; padding: 0 25px; background: rgba(255,255,255,0.02); clip-path: polygon(4% 0, 100% 0, 96% 100%, 0 100%); position: relative; overflow: hidden; }
        .moto-team-color { position: absolute; left: 0; bottom: 0; height: 4px; width: 100%; }
        .moto-driver { font-weight: 900; font-style: italic; font-size: 16px; text-transform: uppercase; letter-spacing: -0.5px; }
        .moto-team { font-weight: 400; font-size: 10px; color: rgba(255,255,255,0.4); margin-left: auto; text-transform: uppercase; }
        .moto-stat { width: 120px; text-align: center; font-size: 14px; font-weight: 700; font-family: 'Chakra Petch'; color: rgba(255,255,255,0.6); }
        .nav-paddle-top { width: 60px; height: 100%; display: flex; align-items: center; justify-content: center; cursor: pointer; transition: all 0.2s; border-left: 1px solid rgba(255,255,255,0.1); }
        .nav-paddle-top:hover { background: #e10600; color: white; }
        .driver-list-item { padding: 10px 14px; border-left: 4px solid transparent; cursor: pointer; transition: all 0.1s; background: rgba(255, 255, 255, 0.02); margin-bottom: 2px; display: flex; align-items: center; }
        .driver-list-item:hover { background: rgba(255, 255, 255, 0.05); }
        .driver-list-item.active { border-left-color: #e10600; background: rgba(225, 6, 0, 0.15); }
        .tps-segment { flex: 1; height: 100%; transform: skewX(-20deg); transition: background-color 0.15s; border: 1px solid rgba(255,255,255,0.05); }
        .checkbox-custom { width: 12px; height: 12px; border: 1px solid rgba(255,255,255,0.3); border-radius: 2px; margin-right: 10px; display: flex; items-center justify-center; transition: all 0.1s; cursor: pointer; }
        .checkbox-custom.checked { background: #e10600; border-color: #e10600; }
        .checkbox-custom.checked::after { content: '✓'; color: white; font-size: 8px; font-weight: 900; }
        .moto-checkbox-cell { width: 40px; height: 100%; display: flex; items-center justify-center; z-index: 10; }
        .pwa-btn { position: relative; background: #1f1f27; border: 1px solid rgba(255,255,255,0.1); color: white; padding: 8px 16px; font-family: 'Orbitron', sans-serif; font-weight: 900; font-style: italic; font-size: 10px; text-transform: uppercase; clip-path: polygon(10% 0, 100% 0, 90% 100%, 0 100%); transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1); overflow: hidden; }
        .pwa-btn::before { content: ''; position: absolute; top: 0; left: -100%; width: 100%; height: 100%; background: linear-gradient(90deg, transparent, rgba(225,6,0,0.4), transparent); transition: 0.5s; }
        .pwa-btn:hover { border-color: #e10600; box-shadow: 0 0 15px rgba(225,6,0,0.3); transform: translateY(-1px); }
        .pwa-btn:hover::before { left: 100%; }
        .pwa-btn span { color: #e10600; margin-right: 8px; }
        .logo-glow { filter: drop-shadow(0 0 8px rgba(225, 6, 0, 0.6)); }
      `}</style>

      {isAnimating && (
        <div className="fixed inset-0 z-[100] bg-black/70 backdrop-blur-sm flex items-center justify-center">
          <div className="bg-[#e10600] w-full h-24 skew-y-[-2deg] flex items-center justify-center shadow-2xl border-y-4 border-white/20">
            <span className="text-white text-5xl font-black italic tracking-tighter uppercase f1-font">PIT STOP...</span>
          </div>
        </div>
      )}

      {showTutorial && <RadioTutorial lap={lap} onDismiss={handleDismissTutorial} />}

      {showExportModal && (
        <div className="fixed inset-0 z-[200] bg-black/90 backdrop-blur-md flex items-center justify-center p-4">
           <div className="bg-[#1f1f27] w-full max-w-xl rounded-lg overflow-hidden border-b-4 border-[#e10600] shadow-[0_0_80px_rgba(225,6,0,0.2)] flex flex-col max-h-[90vh]">
              <div className="p-6 border-b border-white/10 flex justify-between items-center bg-black/20">
                 <h2 className="f1-font font-black italic text-xl uppercase text-white">Export Terminal</h2>
                 <button onClick={() => setShowExportModal(false)} className="text-white/40 hover:text-white transition-colors"><i className="fa-solid fa-xmark text-xl"></i></button>
              </div>
              <div className="flex-1 overflow-y-auto p-8 flex flex-col items-center">
                 <div className="space-y-4 w-full max-w-sm">
                    <p className="text-[10px] font-black italic text-[#e10600] uppercase tracking-widest mb-4 text-center">Session Exports</p>
                    <button onClick={() => exportPDF('selected')} disabled={selectedIds.size === 0} className={`w-full bg-white/5 hover:bg-white/10 p-5 rounded-lg border border-white/10 flex items-center group transition-all text-left ${selectedIds.size === 0 ? 'opacity-30 cursor-not-allowed' : ''}`}>
                       <div className="w-12 h-12 bg-[#e10600] rounded flex items-center justify-center mr-5 group-hover:scale-110 transition-transform shadow-[0_0_20px_rgba(225,6,0,0.4)]">
                          <span className="text-white font-black italic text-sm">{selectedIds.size}</span>
                       </div>
                       <div>
                          <p className="font-black italic text-sm uppercase text-white">Export Selected ({selectedIds.size})</p>
                          <p className="text-[10px] text-white/40 uppercase">選択した {selectedIds.size} 名分のみPDF出力</p>
                       </div>
                    </button>
                    <button onClick={() => exportPDF('single')} className="w-full bg-white/5 hover:bg-white/10 p-5 rounded-lg border border-white/10 flex items-center group transition-all text-left">
                       <div className="w-12 h-12 bg-blue-600 rounded flex items-center justify-center mr-5 group-hover:scale-110 transition-transform"><i className="fa-solid fa-user-check text-xl"></i></div>
                       <div>
                          <p className="font-black italic text-sm uppercase text-white">Current Driver Only</p>
                          <p className="text-[10px] text-white/40 uppercase">現在表示中の1名分のみPDF出力</p>
                       </div>
                    </button>
                    <button onClick={() => exportPDF('all')} className="w-full bg-white/5 hover:bg-white/10 p-5 rounded-lg border border-white/10 flex items-center group transition-all text-left">
                       <div className="w-12 h-12 bg-[#e10600] rounded flex items-center justify-center mr-5 group-hover:scale-110 transition-transform"><i className="fa-solid fa-file-pdf text-xl"></i></div>
                       <div>
                          <p className="font-black italic text-sm uppercase text-white">All Drivers (Single File)</p>
                          <p className="text-[10px] text-white/40 uppercase">全員分の解析を1つの巨大なPDFにまとめます</p>
                       </div>
                    </button>
                    <button onClick={downloadExcel} className="w-full bg-white/5 hover:bg-white/10 p-5 rounded-lg border border-white/10 flex items-center group transition-all text-left">
                       <div className="w-12 h-12 bg-green-600 rounded flex items-center justify-center mr-5 group-hover:scale-110 transition-transform"><i className="fa-solid fa-file-excel text-xl"></i></div>
                       <div>
                          <p className="font-black italic text-sm uppercase text-white">Excel / CSV Data</p>
                          <p className="text-[10px] text-white/40 uppercase">全スコア、大問・観点別得点リストを出力</p>
                       </div>
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {isExporting && (
        <div className="fixed inset-0 z-[500] bg-[#0b0e1b] flex flex-col items-center justify-start p-12 overflow-y-auto overflow-x-hidden">
           <div className="max-w-2xl w-full flex flex-col items-center mb-8 shrink-0">
              <div className="flex flex-col items-center mb-16">
                 <div className="f1-font text-8xl font-black italic text-[#e10600] leading-none mb-4 animate-pulse">{exportProgress}%</div>
                 <h2 className="f1-font text-2xl font-black italic text-white uppercase tracking-tighter">TPS // Throttle Position Sensor</h2>
                 <p className="text-[#00ffd2] text-xs font-black italic uppercase tracking-[0.4em] mt-3">Encoding Telemetry...</p>
              </div>
              <div className="w-full h-16 bg-white/5 border border-white/10 p-2 flex gap-1 rounded-sm overflow-hidden mb-12">
                 {Array.from({ length: 40 }).map((_, i) => (
                   <div key={i} className="tps-segment" style={{ backgroundColor: exportProgress >= (i + 1) * 2.5 ? (i * 2.5 < 40 ? '#00ffd2' : i * 2.5 < 75 ? '#FFF500' : '#e10600') : 'rgba(255,255,255,0.03)' }} />
                 ))}
              </div>
           </div>
           <div id="pdf-render-zone" style={{ position: 'absolute', left: '-9999px', top: '0', width: '210mm', backgroundColor: '#ffffff', zIndex: -1, pointerEvents: 'none' }}>
             {resultsForPdf.map((r) => (
               <div key={r.student.id} id={`pdf-page-${r.student.id}`} style={{ backgroundColor: '#ffffff', width: '210mm', margin: 0, padding: 0 }}>
                 <ResultReport result={getFullDetailResult(r)} sessionTitle={sessionTitle} />
               </div>
             ))}
           </div>
        </div>
      )}

      <header className="h-16 flex items-center px-8 bg-[#060c22] border-b border-white/10 z-50 no-print">
        <div className="flex items-center cursor-pointer group py-1" onClick={() => triggerLapChange(1)}>
          <img src={LOGO_PATH} alt="APEX Logo" className="h-11 w-11 mr-4 rounded-lg border border-white/10 logo-glow group-hover:scale-105 transition-all duration-300" />
          <div className="flex flex-col">
            <span className="text-xl font-black italic tracking-tighter text-white uppercase f1-font leading-none">APEX SCORER</span>
            <span className="text-[10px] font-black italic text-[#e10600] uppercase tracking-[0.3em] ml-0.5 mt-0.5">Grand Prix Edition</span>
          </div>
        </div>
        <div className="ml-auto flex items-center h-full">
          {lap === 1 && deferredPrompt && (
            <button onClick={handleInstallApp} className="pwa-btn mr-4">
              <span><i className="fa-solid fa-microchip"></i></span> Install System
            </button>
          )}
          {lap === 4 && (
            <div className="flex items-center h-full mr-4 border-l border-white/5">
               <button onClick={() => navigateDriver(-1)} className="nav-paddle-top"><i className="fa-solid fa-chevron-left"></i></button>
               <div className="px-6 flex flex-col items-center">
                  <span className="text-[10px] font-black italic text-[#00ffd2] uppercase">Telemetry</span>
                  <span className="text-white font-bold text-xs truncate max-w-[120px]">{selectedFullResult?.student.name}</span>
               </div>
               <button onClick={() => navigateDriver(1)} className="nav-paddle-top"><i className="fa-solid fa-chevron-right"></i></button>
            </div>
          )}
          {rawAnswers.length > 0 && lap <= 3 && (
            <button onClick={() => triggerLapChange(4)} className="bg-[#00ffd2] text-black px-4 py-1.5 rounded-sm font-black italic text-[10px] uppercase mr-4 f1-font">ANALYSIS TERMINAL へ戻る</button>
          )}
          {lap > 1 && <button onClick={() => triggerLapChange(1)} className="text-white/40 text-[10px] font-black uppercase hover:text-white px-4 transition-colors">Home</button>}
          {lap >= 4 && (
            <div className="relative">
              <button onClick={() => setShowExportModal(true)} className="bg-[#e10600] text-white px-6 py-2 font-black italic rounded text-[10px] uppercase f1-font ml-2 hover:scale-105 active:scale-95 transition-transform">
                Export Terminal <i className="fa-solid fa-download ml-2"></i>
              </button>
              {selectedIds.size > 0 && (
                <div className="absolute -top-2 -right-1 bg-[#00ffd2] text-black text-[8px] font-black px-1.5 py-0.5 rounded-full shadow-[0_0_10px_rgba(0,255,210,0.5)]">
                  {selectedIds.size}
                </div>
              )}
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative flex flex-col p-6 max-w-[1400px] mx-auto w-full">
        {lap === 1 && !showSetupEntry && (
          <div className="flex-1 flex flex-col overflow-hidden space-y-12">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div onClick={startNewSession} className="bg-[#1f1f27] border-2 border-white/5 p-10 rounded-xl cursor-pointer hover:border-[#e10600] group transition-all relative overflow-hidden">
                   <div className="absolute top-0 right-0 w-32 h-32 bg-[#e10600]/5 -mr-16 -mt-16 rounded-full group-hover:scale-150 transition-transform"></div>
                   <div className="flex items-center space-x-6">
                      <div className="w-20 h-20 bg-[#e10600] rounded-lg flex items-center justify-center shadow-[0_0_30px_rgba(225,6,0,0.3)] overflow-hidden">
