import React, { useState, useEffect, useCallback } from 'react';
import { Student, Question, StudentAnswer, ScoringResult, ArchiveData, CompetencyType, COMPETENCY_LABELS } from './types';
import { SetupForm } from './components/SetupForm';
import { ResultReport } from './components/ResultReport';

// ロゴ画像はルートディレクトリに logo.png という名前で置いてください
const LOGO_PATH = "logo.png";
const APP_VERSION = "v1.3.7-PRO-GP";

const RadioTutorial: React.FC<{ lap: number, onDismiss: (forever: boolean) => void }> = ({ lap, onDismiss }) => {
  const [showForever, setShowForever] = useState(false);
  const messages: Record<number, string> = {
    1: "Copy that, Driver 1! ホームダッシュボードへようこそ。新しいセッションを開始するか、過去のログからデータを復元してくれ。",
    2: "マシンセッティングの時間だ。正解と配点、それから観点（Competency）を設定してくれ。一括適用ツールを使えばピット作業時間を短縮できるぞ。",
    3: "Box, Box! 解答データ（テレメトリ）をシステムに流し込んでくれ。アップロードが完了すれば、APEXシステムが即座に解析を開始する。",
    4: "Purple Sector! 個別解析ターミナルへようこそ。ここでは一人一人の詳細なミスや傾向を分析できる。左右のパドルでドライバーを切り替えろ。",
    5: "Checkered Flag! セッション終了だ。全ドライバーの最終順位と統計を確認してくれ。エクスポート端末からPDF個票を生成することも可能だ。"
  };

  return (
    <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-[1000] w-full max-w-2xl px-4 animate-[slideUp_0.5s_ease-out]">
      <div className="bg-[#1f1f27] border-l-4 border-[#e10600] shadow-[0_20px_50px_rgba(0,0,0,0.5)] p-5 rounded-r-lg relative overflow-hidden">
        <div className="absolute top-0 right-0 p-2 flex space-x-2">
           <div className="w-1 h-3 bg-[#e10600] animate-pulse"></div>
           <div className="w-1 h-3 bg-[#e10600] animate-pulse delay-75"></div>
           <div className="w-1 h-3 bg-[#e10600] animate-pulse delay-150"></div>
        </div>
        <div className="flex items-start space-x-4">
          <div className="w-12 h-12 bg-white/5 rounded-full flex items-center justify-center border border-white/10 shrink-0">
             <i className="fa-solid fa-headset text-[#e10600] text-xl"></i>
          </div>
          <div className="flex-1">
            <div className="flex items-center space-x-2 mb-1">
               <span className="f1-font text-[10px] font-black italic text-[#e10600] uppercase tracking-widest">Incoming Radio...</span>
               <span className="text-[8px] font-bold text-white/20 uppercase tracking-tighter">Lap {lap} Engineer</span>
            </div>
            <p className="text-white text-sm font-medium leading-relaxed font-mono">
              {messages[lap] || "Stand by for instructions..."}
            </p>
            <div className="mt-4 flex items-center justify-between">
               <label className="flex items-center space-x-2 cursor-pointer group">
                  <input type="checkbox" checked={showForever} onChange={(e) => setShowForever(e.target.checked)} className="w-3 h-3 accent-[#e10600]" />
                  <span className="text-[9px] font-black text-white/30 uppercase group-hover:text-white/60 transition-colors">Don't show this radio again</span>
               </label>
               <button 
                 onClick={() => onDismiss(showForever)}
                 className="bg-white/5 hover:bg-[#e10600] text-white px-4 py-1 rounded text-[9px] font-black italic uppercase transition-all"
               >
                 Copy, Roger!
               </button>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        @keyframes slideUp { from { transform: translate(-50%, 100%); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
      `}</style>
    </div>
  );
};

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [results, setResults] = useState<ScoringResult[]>([]);
  const [rawAnswers, setRawAnswers] = useState<StudentAnswer[]>([]);
  const [lap, setLap] = useState<1 | 2 | 3 | 4 | 5>(1);
  const [archives, setArchives] = useState<ArchiveData[]>([]);
  const [selectedResultIndex, setSelectedResultIndex] = useState<number>(0);
  const [sessionTitle, setSessionTitle] = useState<string>("");
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [showTutorial, setShowTutorial] = useState(false);
  const [tutorialHiddenForever, setTutorialHiddenForever] = useState(false);
  const [showSetupEntry, setShowSetupEntry] = useState(false);

  const refreshArchives = useCallback(() => {
    try {
      const savedArchives = localStorage.getItem('grader_archives');
      if (savedArchives) setArchives(JSON.parse(savedArchives));
      const hidden = localStorage.getItem('grader_tutorial_hidden') === 'true';
      setTutorialHiddenForever(hidden);
    } catch (e) { console.error("Archive load failed", e); }
  }, []);

  useEffect(() => {
    refreshArchives();
    const draft = localStorage.getItem('grader_current_draft');
    if (draft) {
      try {
        const data = JSON.parse(draft);
        if (data.students) setStudents(data.students);
        if (data.questions) setQuestions(data.questions);
        if (data.sessionTitle) setSessionTitle(data.sessionTitle);
        if (data.results) setResults(data.results);
        if (data.rawAnswers) setRawAnswers(data.rawAnswers);
        if (data.currentSessionId) setCurrentSessionId(data.currentSessionId);
      } catch (e) { console.error("Draft load failed", e); }
    }

    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, [refreshArchives]);

  const startNewSession = () => {
    if (students.length > 0 || questions.length > 0) {
      if (!confirm("現在のドラフト設定を破棄して、新しいセッションを開始しますか？")) return;
    }
    setStudents([]);
    setQuestions([]);
    setResults([]);
    setRawAnswers([]);
    setSessionTitle("");
    setCurrentSessionId(null);
    setSelectedResultIndex(0);
    localStorage.removeItem('grader_current_draft');

    setShowSetupEntry(true);
    setLap(1);
  };

  useEffect(() => {
    if (!tutorialHiddenForever) setShowTutorial(true);
  }, [lap, tutorialHiddenForever]);

  const handleDismissTutorial = (forever: boolean) => {
    setShowTutorial(false);
    if (forever) {
      setTutorialHiddenForever(true);
      localStorage.setItem('grader_tutorial_hidden', 'true');
    }
  };

  // Fix: Line 173 shorthand property 'session' renamed to 'sessionTitle' to match state and type definitions
  useEffect(() => {
    const draft = { students, questions, sessionTitle, results, rawAnswers, currentSessionId };
    localStorage.setItem('grader_current_draft', JSON.stringify(draft));
  }, [students, questions, sessionTitle, results, rawAnswers, currentSessionId]);

  const handleProcess = (answers: StudentAnswer[]) => {
    const newResults: ScoringResult[] = answers.map(ans => {
      const student = students.find(s => s.id === ans.studentId) || { id: ans.studentId, name: 'Unknown', class: 'Unknown' };
      let score = 0;
      let totalPoints = 0;

      const details = questions.map(q => {
        const studentAns = ans.answers[q.number] || "";
        const isCorrect = studentAns === q.correctAnswer;
        totalPoints += q.point;
        if (isCorrect) score += q.point;

        return {
          questionNumber: q.number,
          correctAnswer: q.correctAnswer,
          studentAnswer: studentAns,
          isCorrect,
          point: q.point,
          group: q.group,
          competency: q.competency,
        };
      });

      const competencyResults: Record<CompetencyType, any> = {
        none: { label: COMPETENCY_LABELS.none, score: 0, total: 0, percentage: 0 },
        knowledge: { label: COMPETENCY_LABELS.knowledge, score: 0, total: 0, percentage: 0 },
        thinking: { label: COMPETENCY_LABELS.thinking, score: 0, total: 0, percentage: 0 },
        attitude: { label: COMPETENCY_LABELS.attitude, score: 0, total: 0, percentage: 0 },
      };

      details.forEach(d => {
        const comp = competencyResults[d.competency];
        comp.total += d.point;
        if (d.isCorrect) comp.score += d.point;
      });

      Object.keys(competencyResults).forEach(key => {
        const comp = competencyResults[key as CompetencyType];
        comp.percentage = comp.total > 0 ? (comp.score / comp.total) * 100 : 0;
      });

      return {
        student,
        score,
        totalPoints,
        accuracy: totalPoints > 0 ? (score / totalPoints) * 100 : 0,
        competencyResults,
        details
      };
    });

    // Calculate overall accuracy for each question
    const questionAccuracies: Record<number, number> = {};
    questions.forEach(q => {
      const correctCount = answers.filter(a => a.answers[q.number] === q.correctAnswer).length;
      questionAccuracies[q.number] = answers.length > 0 ? (correctCount / answers.length) * 100 : 0;
    });

    newResults.forEach(res => {
      res.details.forEach(d => {
        (d as any).overallAccuracy = questionAccuracies[d.questionNumber];
      });
    });

    setResults(newResults);
    setRawAnswers(answers);
    setLap(4);
  };

  const archiveSession = () => {
    const newArchive: ArchiveData = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleString(),
      name: sessionTitle || "Untitled Session",
      results,
      questions,
      students,
      rawAnswers
    };
    const updatedArchives = [newArchive, ...archives];
    localStorage.setItem('grader_archives', JSON.stringify(updatedArchives));
    setArchives(updatedArchives);
    alert("セッションを保存しました。");
  };

  // Added return statement to fix 'Type () => void is not assignable to type FC' error at line 63
  return (
    <div className="min-h-screen bg-[#15151e] text-white flex flex-col font-sans">
      {showTutorial && <RadioTutorial lap={lap} onDismiss={handleDismissTutorial} />}

      <header className="bg-[#1f1f27] border-b border-white/10 px-6 py-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center space-x-6">
          <div className="bg-[#e10600] p-2 rounded transform -skew-x-12">
            <span className="f1-font font-black italic text-white px-2">APEX GRADER</span>
          </div>
          <div className="h-6 w-px bg-white/10"></div>
          <span className="f1-font text-[10px] font-black italic text-white/40 tracking-[0.2em]">{APP_VERSION}</span>
        </div>

        {results.length > 0 && (
          <div className="flex items-center space-x-4">
             <button onClick={archiveSession} className="f1-font text-[10px] font-black italic text-white/60 hover:text-white uppercase transition-colors">Save</button>
             <button onClick={startNewSession} className="bg-white/5 hover:bg-white/10 text-white px-4 py-1 rounded f1-font text-[10px] font-black italic uppercase border border-white/10 transition-all">New Start</button>
          </div>
        )}
      </header>

      <main className="flex-1 flex flex-col p-6 overflow-hidden">
        {!showSetupEntry && results.length === 0 && (
          <div className="max-w-4xl mx-auto w-full mt-20">
            <div className="bg-[#1f1f27] p-12 rounded-lg border-b-8 border-[#e10600] text-center shadow-2xl">
              <h1 className="f1-font text-6xl font-black italic mb-4 uppercase tracking-tighter">Apex Grader</h1>
              <p className="text-white/40 mb-12 font-medium italic">Advanced Assessment Telemetry & Analysis</p>
              <div className="grid grid-cols-2 gap-6">
                 <button onClick={startNewSession} className="bg-[#e10600] text-white p-8 rounded-xl flex flex-col items-center group transition-all hover:scale-105">
                   <i className="fa-solid fa-flag-checkered text-4xl mb-4 group-hover:rotate-12 transition-transform"></i>
                   <span className="f1-font text-xl font-black italic uppercase">New Session</span>
                 </button>
                 <button onClick={() => setShowSetupEntry(true)} className="bg-white/5 border border-white/10 text-white p-8 rounded-xl flex flex-col items-center group transition-all hover:bg-white/10">
                   <i className="fa-solid fa-rotate-left text-4xl mb-4 text-white/40"></i>
                   <span className="f1-font text-xl font-black italic uppercase">Resume Draft</span>
                 </button>
              </div>
            </div>

            {archives.length > 0 && (
              <div className="mt-12">
                <h3 className="f1-font text-sm font-black italic text-white/40 uppercase mb-4 tracking-widest">Grand Prix History</h3>
                <div className="grid grid-cols-2 gap-4">
                  {archives.slice(0, 4).map(arc => (
                    <div key={arc.id} onClick={() => {
                      setStudents(arc.students);
                      setQuestions(arc.questions);
                      setResults(arc.results);
                      setSessionTitle(arc.name);
                      setRawAnswers(arc.rawAnswers || []);
                      setLap(5);
                    }} className="bg-[#1f1f27] p-4 rounded border border-white/5 hover:border-[#00ffd2] cursor-pointer transition-all group">
                      <div className="flex justify-between items-center">
                         <span className="f1-font font-black italic text-sm group-hover:text-[#00ffd2]">{arc.name}</span>
                         <span className="text-[9px] font-bold text-white/20">{arc.timestamp}</span>
                      </div>
                      <div className="mt-2 text-[9px] font-bold text-white/40 uppercase">{arc.results.length} Drivers Recorded</div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {(showSetupEntry || results.length > 0) && (
          <div className="flex-1 flex flex-col overflow-hidden">
             {lap <= 3 ? (
               <SetupForm 
                 lap={lap as 1 | 2 | 3} 
                 setLap={setLap} 
                 students={students} 
                 setStudents={setStudents} 
                 questions={questions} 
                 setQuestions={setQuestions} 
                 onProcess={handleProcess} 
                 sessionTitle={sessionTitle}
                 setSessionTitle={setSessionTitle}
                 resetSession={() => setShowSetupEntry(false)}
               />
             ) : (
               <div className="flex-1 flex flex-col overflow-hidden">
                  <div className="mb-6 flex items-center justify-between no-print">
                     <div className="flex items-center space-x-6">
                        <button onClick={() => setLap(3)} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:bg-white/10"><i className="fa-solid fa-arrow-left"></i></button>
                        <div>
                          <h2 className="f1-font text-2xl font-black italic uppercase leading-none">{lap === 4 ? 'Individual Data' : 'Final Standings'}</h2>
                          <div className="flex items-center space-x-4 mt-2">
                             <button onClick={() => setLap(4)} className={`text-[10px] font-black italic uppercase transition-colors ${lap === 4 ? 'text-[#00ffd2]' : 'text-white/40 hover:text-white'}`}>Terminal</button>
                             <button onClick={() => setLap(5)} className={`text-[10px] font-black italic uppercase transition-colors ${lap === 5 ? 'text-[#00ffd2]' : 'text-white/40 hover:text-white'}`}>Standings</button>
                          </div>
                        </div>
                     </div>
                     <button onClick={() => window.print()} className="bg-[#00ffd2] text-black px-6 py-2 f1-font font-black italic rounded skew-x-[-10deg] text-xs uppercase shadow-[0_0_15px_rgba(0,255,210,0.3)]">Generate Reports</button>
                  </div>

                  {lap === 4 && (
                    <div className="flex-1 flex overflow-hidden gap-6">
                       <div className="w-80 bg-[#1f1f27] rounded border border-white/10 flex flex-col overflow-hidden">
                          <div className="flex-1 overflow-y-auto">
                             {results.map((res, idx) => (
                               <div key={res.student.id} onClick={() => setSelectedResultIndex(idx)} className={`p-4 border-b border-white/5 cursor-pointer transition-all ${selectedResultIndex === idx ? 'bg-[#e10600]/10 border-l-4 border-l-[#e10600]' : 'hover:bg-white/5'}`}>
                                  <div className="f1-font font-black italic text-xs uppercase">{res.student.name}</div>
                                  <div className="text-[9px] font-bold text-white/20 mt-1 tracking-widest uppercase">{res.student.id} // {res.student.class}</div>
                               </div>
                             ))}
                          </div>
                       </div>
                       <div className="flex-1 bg-white rounded overflow-y-auto print:overflow-visible shadow-inner">
                          {results[selectedResultIndex] && (
                            <ResultReport result={results[selectedResultIndex]} sessionTitle={sessionTitle} />
                          )}
                       </div>
                    </div>
                  )}

                  {lap === 5 && (
                    <div className="flex-1 overflow-y-auto bg-[#1f1f27] rounded border border-white/10 shadow-2xl">
                       <table className="w-full text-left">
                          <thead className="bg-black/40 border-b border-white/10 sticky top-0">
                             <tr>
                                <th className="p-4 f1-font text-[10px] font-black italic uppercase text-white/40">Pos</th>
                                <th className="p-4 f1-font text-[10px] font-black italic uppercase text-white/40">Driver</th>
                                <th className="p-4 f1-font text-[10px] font-black italic uppercase text-white/40 text-right">Score</th>
                                <th className="p-4 f1-font text-[10px] font-black italic uppercase text-white/40 text-right">Accuracy</th>
                             </tr>
                          </thead>
                          <tbody>
                             {[...results].sort((a,b) => b.score - a.score).map((res, idx) => (
                               <tr key={res.student.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                                  <td className="p-4 f1-font font-black italic text-[#e10600]">{idx + 1}</td>
                                  <td className="p-4 font-bold">{res.student.name}</td>
                                  <td className="p-4 text-right f1-font font-black italic text-lg">{res.score}</td>
                                  <td className="p-4 text-right font-mono text-sm text-[#00ffd2]">{res.accuracy.toFixed(1)}%</td>
                               </tr>
                             ))}
                          </tbody>
                       </table>
                    </div>
                  )}
               </div>
             )}
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

