                    <div className={`moto-pos ${absRank === 1 ? 'top1' : absRank === 2 ? 'top2' : absRank === 3 ? 'top3' : ''}`} onClick={() => { 
                        const idx = sidebarList.findIndex(res => res.student.id === r.student.id);
                        if (idx !== -1) setSelectedResultIndex(idx);
                        triggerLapChange(4); 
                      }}>{absRank}</div>
                    <div className="moto-pts">{r.score}</div>
                    <div className="moto-name-block" onClick={() => { 
                        const idx = sidebarList.findIndex(res => res.student.id === r.student.id);
                        if (idx !== -1) setSelectedResultIndex(idx);
                        triggerLapChange(4); 
                      }}>
                       <div className="moto-team-color" style={{ backgroundColor: getClassColor(r.student.class) }}></div>
                       <span className="moto-driver">{r.student.name}</span>
                       <span className="moto-team">{r.student.class}</span>
                    </div>
                    <div className="moto-stat">{r.accuracy.toFixed(1)}%</div>
                  </div>
                );
              })}
            </div>
            <div className="mt-8 grid grid-cols-4 gap-4">
               <div className="bg-[#1f1f27] p-5 rounded border-l-4 border-[#00ffd2]">
                  <p className="text-[10px] font-black text-white/30 uppercase tracking-widest">Average Score</p>
                  <p className="text-3xl font-black italic f1-font text-[#00ffd2]">{overallAverage.toFixed(1)}</p>
               </div>
               <div className="bg-[#1f1f27] p-5 rounded border-l-4 border-[#e10600]">
                  <p className="text-[10px] font-black text-white/30 uppercase tracking-widest">Total Drivers</p>
                  <p className="text-3xl font-black italic f1-font">{results.length}</p>
               </div>
               <div className="col-span-2 bg-[#1f1f27] p-5 rounded flex items-center justify-between">
                  <div className="flex items-center space-x-8">
                    {sortedClassNames.slice(0, 4).map(cls => (
                      <div key={cls} className="flex flex-col cursor-pointer hover:opacity-80 transition-all" onClick={() => setFilterClass(cls)}>
                        <span className="text-[9px] font-black text-white/20 uppercase">{cls}</span>
                        <span className="font-black italic text-lg" style={{ color: getClassColor(cls) }}>
                          { classStats[cls] ? (classStats[cls].totalScore / classStats[cls].count).toFixed(1) : "0.0" }
                        </span>
                      </div>
                    ))}
                  </div>
                  <span className="text-[10px] font-black italic text-white/10 uppercase tracking-widest">Constructor Metrics</span>
               </div>
            </div>
          </div>
        )}
      </main>
      <footer className="h-8 bg-[#060c22] border-t border-white/5 flex items-center px-8 no-print shrink-0 justify-between">
        <div className="text-[8px] font-bold text-white/20 uppercase tracking-widest">FIA DATA STREAM // PERSISTENCE ACTIVE</div>
        <div className="text-[8px] font-bold text-white/20 uppercase tracking-widest f1-font italic">Copyright © Ken Magami. All Rights Reserved.</div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Student, Question, StudentAnswer, CompetencyType, COMPETENCY_LABELS } from '../types';

interface SetupFormProps {
  lap: 1 | 2 | 3 | 4;
  setLap: (lap: any) => void;
  students: Student[];
  setStudents: (s: Student[]) => void;
  questions: Question[];
  setQuestions: (q: Question[] | ((prev: Question[]) => Question[])) => void;
  onProcess: (answers: StudentAnswer[]) => void;
  sessionTitle: string;
  setSessionTitle: (t: string) => void;
  resetSession?: () => void;
}

type DragMode = 'none' | 'point' | 'group' | 'competency';
type UploadStatus = 'idle' | 'processing' | 'success' | 'error';

interface RangeSlot {
  group: string;
  start: number;
  end: number;
  selected: boolean;
}

export const SetupForm: React.FC<SetupFormProps> = ({
  lap, setLap, students, setStudents, questions, setQuestions, onProcess,
  sessionTitle, setSessionTitle, resetSession
}) => {
  const [qCount, setQCount] = useState(questions.length || 10);
  const [dragMode, setDragMode] = useState<DragMode>('none');
  const [activeValue, setActiveValue] = useState<number | null>(null);
  const [activeComp, setActiveComp] = useState<CompetencyType | null>(null);
  const [showBulkPaste, setShowBulkPaste] = useState(false);
  const [bulkInput, setBulkInput] = useState("");
  const [uploadStatus, setUploadStatus] = useState<UploadStatus>('idle');

  const [rangeSlots, setRangeSlots] = useState<RangeSlot[]>([]);
  const [flashingQs, setFlashingQs] = useState<Set<number>>(new Set());

  const flashEffect = (numbers: number[]) => {
    setFlashingQs(new Set(numbers));
    setTimeout(() => setFlashingQs(new Set()), 600);
  };

  const handleStudentUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result;
      if (typeof result !== 'string') return;
      const csvLines = result.split(/\r?\n/).filter(line => line.trim() !== "");
      const parsed = csvLines.slice(1).map(line => {
        const [grade, cls, num, name] = line.split(',').map(s => s.trim());
        if (!grade || !cls || !num) return null;
        const paddedNum = num.padStart(2, '0');
        const id = `${grade}${cls}${paddedNum}`;
        return { id, name: name || `生徒 ${paddedNum}`, class: `${grade}年${cls}組` };
      }).filter((s): s is Student => s !== null);
      setStudents(parsed);
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const downloadStudentTemplate = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const csvContent = "grade,class,number,name\n1,A,01,山田 太郎\n1,A,02,佐藤 花子";
    const blob = new Blob([bom, csvContent], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'driver_entry_template.csv'; a.click();
  };

  useEffect(() => {
    if (lap === 2 && questions.length === 0) {
      const initQ = Array.from({ length: qCount }, (_, i) => ({
        number: i + 1, correctAnswer: '', point: 5, group: '', competency: 'none' as CompetencyType
      }));
      setQuestions(initQ);
    }
  }, [lap, qCount, questions.length, setQuestions]);

  const syncGroupNumbers = () => {
    if (rangeSlots.length === 0) return;
    setQuestions((prev: Question[]) => {
      const next = prev.map(q => {
        const matchingSlot = [...rangeSlots].reverse().find(s => q.number >= s.start && q.number <= s.end);
        if (matchingSlot && q.group !== matchingSlot.group) {
          return { ...q, group: matchingSlot.group };
        }
        return q;
      });
      return next;
    });
  };

  useEffect(() => {
    if (lap === 2) syncGroupNumbers();
  }, [rangeSlots, lap, qCount]);

  const updateQ = (no: number, field: keyof Question, val: any) => {
    setQuestions((prev: Question[]) => prev.map(q => q.number === no ? { ...q, [field]: val } : q));
  };

  const applyValueToSelectedGroups = (field: 'point' | 'competency', value: any) => {
    if (value === null) return;
    const selectedGroupIds = rangeSlots.filter(s => s.selected).map(s => s.group.trim());
    if (selectedGroupIds.length === 0) return;
    const affected: number[] = [];
    setQuestions((prev: Question[]) => prev.map(q => {
      if (selectedGroupIds.includes(q.group.trim())) {
        affected.push(q.number);
        return { ...q, [field]: value };
      }
      return q;
    }));
    flashEffect(affected);
  };

  const updateQCount = (val: number) => {
    if (isNaN(val) || val < 1) return;
    const limitedVal = Math.min(val, 200);
    setQCount(limitedVal);
    setQuestions((prev: Question[]) => {
      const newQs = Array.from({ length: limitedVal }, (_, i) => {
        const existing = prev.find(p => p.number === i + 1);
        return existing || { number: i + 1, correctAnswer: '', point: 5, group: '', competency: 'none' as CompetencyType };
      });
      return newQs;
    });
  };

  const downloadAnswersTemplate = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const headers = ["student_id", ...questions.map(q => `Q${q.number}`)].join(',');
    const rows = students.map(s => `${s.id},${questions.map(() => "").join(',')}`).join('\n');
    const csvContent = `${headers}\n${rows}`;
    const blob = new Blob([bom, csvContent], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'telemetry_upload_sheet.csv'; a.click();
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploadStatus('processing');
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const result = event.target?.result;
        if (typeof result !== 'string') throw new Error("File read error");
        const lines = result.split(/\r?\n/).filter(line => line.trim() !== "");
        const answers: StudentAnswer[] = lines.slice(1).map((line) => {
          const parts = line.split(',').map(s => s.trim());
          if (parts.length < 2) return null;
          const ansMap: Record<number, string> = {};
          questions.forEach((q, idx) => { ansMap[q.number] = parts[idx + 1] || ""; });
          return { studentId: parts[0], answers: ansMap };
        }).filter((a): a is StudentAnswer => a !== null && a.studentId !== "");
        setTimeout(() => { onProcess(answers); }, 800);
      } catch (err) { setUploadStatus('error'); }
    };
    reader.readAsText(file);
  };

  const clearRangeSlotsSelection = () => {
    setRangeSlots(prev => prev.map(s => ({ ...s, selected: false })));
  };

  const selectedCount = rangeSlots.filter(s => s.selected).length;

  return (
    <div className="flex-1 flex flex-col space-y-8">
      <style>{`
        input::-webkit-outer-spin-button, input::-webkit-inner-spin-button { -webkit-appearance: none; margin: 0; }
        input[type=number] { -moz-appearance: textfield; }
        .compact-scroll::-webkit-scrollbar { width: 4px; }
        .compact-scroll::-webkit-scrollbar-thumb { background: rgba(225, 6, 0, 0.3); border-radius: 2px; }
        @keyframes flash-green { 0% { background-color: rgba(0, 255, 210, 0.6); transform: scale(1.02); } 100% { background-color: transparent; transform: scale(1); } }
        .animate-flash { animation: flash-green 0.6s cubic-bezier(0.4, 0, 0.2, 1); z-index: 50; }
      `}</style>

      {lap === 1 && (
        <div className="max-w-4xl mx-auto w-full space-y-8">
           <div className="bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600]">
              <h2 className="f1-font text-3xl font-black italic mb-2 uppercase tracking-tighter text-white">Lap 1: Driver Entry</h2>
              <div className="mb-8 space-y-4">
                 <label className="text-white/40 uppercase text-xs font-bold tracking-widest block">セッションタイトル設定</label>
                 <input type="text" value={sessionTitle} onChange={(e) => setSessionTitle(e.target.value)} placeholder="例：2024年度 第1回 実力テスト" className="w-full bg-black border border-white/10 rounded p-4 text-white f1-font text-lg focus:border-[#00ffd2] transition-colors outline-none" />
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-12">
                <button onClick={downloadStudentTemplate} className="h-48 border-2 border-dashed border-white/10 rounded-xl flex flex-col items-center justify-center hover:bg-white/5 transition-all group">
                   <i className="fa-solid fa-file-csv text-5xl text-white/20 group-hover:text-white transition-all mb-4"></i>
                   <span className="f1-font text-sm italic font-bold uppercase tracking-tight text-white/60">1. TEMPLATE DOWNLOAD</span>
                </button>
                <div className="h-48 border-2 border-dashed border-white/10 rounded-xl flex flex-col items-center justify-center relative hover:bg-white/5 transition-all overflow-hidden group">
                   <input type="file" accept=".csv" onChange={handleStudentUpload} className="absolute inset-0 opacity-0 cursor-pointer z-10" />
                   <i className="fa-solid fa-cloud-arrow-up text-5xl text-[#e10600] mb-4 group-hover:scale-110 transition-transform"></i>
                   <span className="f1-font text-sm italic font-bold uppercase tracking-tight text-white/60">2. UPLOAD DRIVER CSV</span>
                </div>
              </div>
              {students.length > 0 && (
                <div className="mt-8 flex flex-col space-y-4">
                  <div className="flex items-center justify-between bg-[#00ffd2]/10 p-6 rounded-lg border border-[#00ffd2]/30">
                    <div className="flex flex-col">
                        <span className="f1-font font-black italic text-[#00ffd2] text-xl uppercase leading-none">{students.length} DRIVERS REGISTERED</span>
                        <span className="text-white/40 text-[10px] font-bold uppercase tracking-widest mt-2">TECHNICAL SETUP IS READY TO START</span>
                    </div>
                    <div className="flex space-x-4">
                      <button onClick={() => resetSession && resetSession()} className="f1-font border border-[#e10600] text-[#e10600] px-8 py-4 font-black italic rounded skew-x-[-10deg] hover:bg-[#e10600] hover:text-white transition-all uppercase text-sm">
                        CANCEL ENTRY
                      </button>
                      <button onClick={() => setLap(2)} className="f1-font bg-[#00ffd2] text-black px-12 py-4 font-black italic rounded skew-x-[-10deg] shadow-[0_0_25px_rgba(0,255,210,0.3)] hover:scale-110 transition-transform uppercase text-sm">
                        START TECH SETUP <i className="fa-solid fa-chevron-right ml-2"></i>
                      </button>
                    </div>
                  </div>
                </div>
              )}
           </div>
        </div>
      )}

      {lap === 2 && (
        <div className="flex-1 flex flex-col overflow-hidden">
           <div className="bg-[#1f1f27] p-4 rounded-t border-b border-white/10 flex items-center justify-between no-print relative">
              <div className="flex items-center space-x-6">
                 <button onClick={() => setLap(1)} className="w-8 h-8 rounded-full border border-white/20 flex items-center justify-center hover:bg-white/5 text-white/60"><i className="fa-solid fa-arrow-left text-xs"></i></button>
                 <div className="flex flex-col">
                    <h2 className="f1-font text-xl font-black italic uppercase leading-none text-white">Lap 2: Technical Setup</h2>
                    <p className="text-white/40 uppercase text-[9px] font-bold tracking-widest mt-1">配点、正解、観点を設定してください。</p>
                 </div>
                 <div className="h-10 w-px bg-white/10 mx-2"></div>
                 <div className="flex flex-col">
                    <label className="text-[9px] font-black text-[#e10600] uppercase mb-1 f1-font italic">Questions</label>
                    <div className="flex items-center bg-black border border-white/20 rounded h-10 overflow-hidden focus-within:border-[#00ffd2]">
                      <input type="number" min="1" max="200" value={qCount} onChange={(e) => updateQCount(parseInt(e.target.value))} className="bg-transparent text-white w-14 px-2 f1-font text-sm font-black text-center outline-none" />
                    </div>
                 </div>
              </div>
              <div className="flex items-center space-x-4">
                <button onClick={() => setShowBulkPaste(true)} className="bg-white/5 hover:bg-white/10 border border-white/20 text-white px-4 py-2 f1-font italic font-bold rounded uppercase text-[10px]"><i className="fa-solid fa-paste mr-2"></i>正解一括</button>
                <button onClick={() => setLap(3)} className="f1-font bg-[#e10600] text-white px-8 py-2.5 font-black italic rounded skew-x-[-10deg] hover:scale-105 shadow-[0_0_15px_rgba(225,6,0,0.3)] text-xs uppercase">NEXT LAP</button>
              </div>
           </div>

           <div className="flex-1 overflow-hidden flex">
              <div className="w-80 bg-[#1f1f27] border-r border-white/10 flex flex-col no-print overflow-y-auto compact-scroll p-4 space-y-6">
                   <div className="p-3 rounded border border-white/10 bg-black/30">
                      <div className="flex justify-between items-center mb-3">
                         <span className="text-[10px] font-black f1-font italic uppercase text-white/60">大問スロット</span>
                         <div className="flex space-x-2">
                           {rangeSlots.length > 0 && (
                             <button onClick={clearRangeSlotsSelection} className="text-white/30 hover:text-[#e10600] transition-colors" title="選択解除">
                               <i className="fa-solid fa-square-xmark"></i>
                             </button>
                           )}
                           <button onClick={() => setRangeSlots([...rangeSlots, { group: (rangeSlots.length + 1).toString(), start: 1, end: 10, selected: false }])} className="text-[#00ffd2] hover:scale-110 transition-transform"><i className="fa-solid fa-circle-plus"></i></button>
                         </div>
                      </div>
                      <div className="space-y-2 max-h-40 overflow-y-auto pr-1 compact-scroll">
                        {rangeSlots.map((slot, idx) => (
                          <div key={idx} className={`flex items-center space-x-1.5 p-1.5 rounded transition-colors ${slot.selected ? 'bg-[#00ffd2]/10 border border-[#00ffd2]/30' : 'bg-white/5 border border-transparent'}`}>
                            <input type="checkbox" checked={slot.selected} onChange={(e) => { const n = [...rangeSlots]; n[idx].selected = e.target.checked; setRangeSlots(n); }} className="w-3 h-3 accent-[#00ffd2]" />
                            <input type="text" value={slot.group} onChange={(e) => { const n = [...rangeSlots]; n[idx].group = e.target.value; setRangeSlots(n); }} className="bg-black border border-white/10 rounded px-1.5 py-1 text-[10px] w-8 text-[#00ffd2] f1-font text-center" />
                            <input type="number" value={slot.start} onChange={(e) => { const n = [...rangeSlots]; n[idx].start = parseInt(e.target.value) || 1; setRangeSlots(n); }} className="bg-black border border-white/10 rounded px-1.5 py-1 text-[10px] w-9 text-white text-center" />
                            <span className="text-white/20 text-[10px]">~</span>
                            <input type="number" value={slot.end} onChange={(e) => { const n = [...rangeSlots]; n[idx].end = parseInt(e.target.value) || 1; setRangeSlots(n); }} className="bg-black border border-white/10 rounded px-1.5 py-1 text-[10px] w-9 text-white text-center" />
                          </div>
                        ))}
                      </div>
                   </div>

                   <div className="p-3 rounded border border-white/10 bg-black/30">
                      <span className="text-[10px] font-black f1-font italic uppercase text-white/60 block mb-3">配点・観点 一括適用</span>
                      <div className="flex flex-col space-y-2 mb-3">
                        <div className="grid grid-cols-5 gap-1">
                           {[1, 2, 3, 4, 5].map(v => (
                             <button key={v} onClick={() => setActiveValue(v)} className={`py-1.5 text-[10px] font-black rounded border ${activeValue === v ? 'bg-[#e10600] border-[#e10600]' : 'bg-black/40 border-white/10 text-white/40'}`}>{v}</button>
                           ))}
                        </div>
                        <div className="flex items-center space-x-2 bg-black/40 border border-white/10 rounded p-1">
                           <span className="text-[8px] font-black text-white/30 uppercase ml-1">Custom:</span>
                           <input 
                             type="number" 
                             step="0.1"
                             placeholder="ANY" 
                             onChange={(e) => setActiveValue(parseFloat(e.target.value) || null)} 
                             className="flex-1 bg-transparent text-white f1-font text-[11px] font-black text-center outline-none focus:text-[#00ffd2]"
                           />
                        </div>
                      </div>
                      <div className="grid grid-cols-1 gap-1 mb-4">
                         {(Object.keys(COMPETENCY_LABELS) as CompetencyType[]).map(k => (
                           <button key={k} onClick={() => setActiveComp(k)} className={`py-1.5 text-[8px] font-black rounded border text-left px-2 truncate ${activeComp === k ? 'bg-blue-600 border-blue-600' : 'bg-black/40 border-white/10 text-white/40'}`}>{COMPETENCY_LABELS[k]}</button>
                         ))}
                      </div>
                      <div className="space-y-2">
                        <button disabled={selectedCount === 0 || activeValue === null} onClick={() => applyValueToSelectedGroups('point', activeValue)} className="w-full py-2 f1-font text-[10px] font-black italic rounded bg-[#e10600] disabled:opacity-20 uppercase">APPLY POINTS</button>
                        <button disabled={selectedCount === 0 || activeComp === null} onClick={() => applyValueToSelectedGroups('competency', activeComp)} className="w-full py-2 f1-font text-[10px] font-black italic rounded bg-blue-600 disabled:opacity-20 uppercase">APPLY COMPETENCY</button>
                      </div>
                   </div>
              </div>

              <div className="flex-1 overflow-y-auto p-4 bg-black/20 compact-scroll">
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 2xl:grid-cols-8 gap-3">
                   {questions.map(q => (
                     <div key={q.number} className={`bg-[#1f1f27] border border-white/10 rounded overflow-hidden flex flex-col ${flashingQs.has(q.number) ? 'animate-flash' : ''}`}>
                        <div className="bg-white/5 p-2 flex justify-between items-center border-b border-white/10">
                           <span className="f1-font font-black italic text-[10px] text-[#e10600]">Q{q.number.toString().padStart(2, '0')}</span>
                           <input type="number" step="0.1" value={q.point} onChange={(e) => updateQ(q.number, 'point', parseFloat(e.target.value) || 0)} className="bg-black/40 w-8 py-0.5 rounded f1-font text-[10px] text-center border border-white/10" />
                        </div>
                        <div className="p-2 space-y-2">
                           <input type="text" maxLength={1} value={q.correctAnswer} onChange={(e) => updateQ(q.number, 'correctAnswer', e.target.value.toUpperCase())} placeholder="正解" className="w-full bg-black/40 border border-white/5 rounded p-1 text-center font-black f1-font text-[#00ffd2] outline-none text-lg" />
                           <select value={q.competency} onChange={(e) => updateQ(q.number, 'competency', e.target.value as any)} className="w-full bg-black text-[8px] p-1 rounded border border-white/10 text-white/60">
                             {(Object.keys(COMPETENCY_LABELS) as CompetencyType[]).map(k => <option key={k} value={k}>{COMPETENCY_LABELS[k]}</option>)}
                           </select>
                        </div>
                     </div>
                   ))}
                </div>
              </div>
           </div>
        </div>
      )}

      {lap === 3 && (
        <div className="max-w-4xl mx-auto w-full space-y-8 flex-1 flex flex-col">
           <div className="bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600] flex-1 flex flex-col">
              <div className="flex items-center space-x-4 mb-8">
                <button onClick={() => setLap(2)} className="w-10 h-10 rounded-full border border-white/20 flex items-center justify-center hover:bg-white/5"><i className="fa-solid fa-arrow-left"></i></button>
                <h2 className="f1-font text-3xl font-black italic uppercase">Lap 3: Data Analysis</h2>
              </div>
              <div className="grid grid-cols-2 gap-8 flex-1">
                <button onClick={downloadAnswersTemplate} className="border-2 border-dashed border-white/10 rounded-xl flex flex-col items-center justify-center hover:bg-white/5 p-12 group transition-all">
                   <i className="fa-solid fa-file-export text-6xl text-[#00ffd2] mb-6 group-hover:scale-110"></i>
                   <span className="f1-font text-lg italic font-bold uppercase tracking-tight text-white/60">1. DOWNLOAD TEMPLATE</span>
                </button>
                <div className="border-2 border-dashed border-white/10 rounded-xl flex flex-col items-center justify-center relative hover:bg-white/5 p-12 group transition-all">
                   <input type="file" accept=".csv" onChange={handleFinalUpload} className="absolute inset-0 opacity-0 cursor-pointer z-10" />
                   <i className="fa-solid fa-microchip text-6xl text-[#e10600] mb-6 group-hover:rotate-12"></i>
                   <span className="f1-font text-lg italic font-bold uppercase tracking-tight text-white/60">2. UPLOAD DATA</span>
                </div>
              </div>
           </div>
        </div>
      )}

      {showBulkPaste && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
           <div className="bg-[#1f1f27] w-full max-w-lg rounded border-b-4 border-[#00ffd2]">
              <div className="p-4 border-b border-white/10 flex justify-between items-center"><h3 className="f1-font font-black italic text-base uppercase">Bulk Paste</h3></div>
              <div className="p-6">
                 <textarea value={bulkInput} onChange={(e) => setBulkInput(e.target.value)} className="w-full h-40 bg-black border border-white/10 rounded p-4 text-[#00ffd2] font-mono text-xl outline-none" placeholder="12345ABCD..." />
                 <div className="mt-6 flex justify-end space-x-3">
                   <button onClick={() => setShowBulkPaste(false)} className="px-6 py-2 f1-font text-[10px] italic font-bold text-white/40">CANCEL</button>
                   <button onClick={() => { 
                     const chars = bulkInput.replace(/\s/g, '').split('');
                     setQuestions(prev => prev.map((q, i) => ({ ...q, correctAnswer: chars[i] ? chars[i].toUpperCase() : q.correctAnswer })));
                     setShowBulkPaste(false);
                   }} className="bg-[#00ffd2] text-black px-10 py-2.5 f1-font text-[10px] italic font-black rounded skew-x-[-10deg]">APPLY</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export interface Student {
  id: string;
  name: string;
  class: string;
}

export type CompetencyType = 'none' | 'knowledge' | 'thinking' | 'attitude';

export const COMPETENCY_LABELS: Record<CompetencyType, string> = {
  none: 'なし',
  knowledge: '知識・技能',
  thinking: '思考・判断・表現',
  attitude: '主体的に学習に取り組む態度'
};

export interface Question {
  number: number;
  correctAnswer: string;
  point: number;
  group: string; // 大問番号 (1, 2, 3...)
  competency: CompetencyType;
}

export interface CompetencyResult {
  label: string;
  score: number;
  total: number;
  percentage: number;
}

export interface StudentAnswer {
  studentId: string;
  answers: Record<number, string>;
}

export interface ScoringResult {
  student: Student;
  score: number;
  totalPoints: number;
  accuracy: number;
  competencyResults: Record<CompetencyType, CompetencyResult>;
  details: {
    questionNumber: number;
    correctAnswer: string;
    studentAnswer: string;
    isCorrect: boolean;
    point: number;
    group: string;
    competency: CompetencyType;
    overallAccuracy?: number;
  }[];
}

export interface ArchiveData {
  id: string;
  timestamp: string;
  name: string;
  results: ScoringResult[];
  questions: Question[];
  students: Student[];
  rawAnswers: StudentAnswer[]; // 再開時の個票生成に必要
}

export interface RangeSlot {
  group: string;
  start: number;
  end: number;
  selected: boolean;
}

