             </div>

             <div className="flex-1 flex flex-col overflow-hidden">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="f1-font text-xl font-black italic text-white/30 uppercase tracking-widest"><i className="fa-solid fa-clock-rotate-left mr-3"></i> ARCHIVED LOGS</h3>
                  <span className="text-[10px] font-black text-white/10 uppercase tracking-widest">{archives.length} HISTORY FILES FOUND</span>
